void IlRtedgeSlots_BindEgEntry(void)
{
#if IL_EGAPI_PLCP_RTEDGE
	size_t i;

	for (i = 0; i < sizeof(il_slot_binds) / sizeof(il_slot_binds[0]); i++) {
		TagsDesc *td = NULL;
		const char *tag = il_slot_binds[i].tag;

		if (EgTagGetProperty(tag, "Entry", &td, sizeof(td)) != EDGE_SUCCESS || td == NULL)
			continue;
		*il_slot_binds[i].pstore = il_rtglue_dataptr_from_tagdesc(td);
	}
#else
	(void)il_slot_binds;
#endif
}

void IlRtedgeTags_Init(void)
{
	hugeplc_ascii2_slots_init();
#if IL_EGAPI_PLCP_RTEDGE
	IlRtedgeSlots_BindEgEntry();
#endif
}
